input.contents:
/* Maestro — تكامل قالب Mazer (Bootstrap 5) + RTL — محاذاة ومسافات منطقية (logical properties) */

body.maestro-mazer {
  --maestro-mazer-sidebar-width: 320px;
  --maestro-admin-space-inline-xs: 0.5rem;
  --maestro-admin-space-inline-sm: 0.75rem;
  --maestro-admin-space-inline-md: 1rem;
  --maestro-admin-space-block-sm: 0.75rem;
  --maestro-admin-space-block-md: 1rem;
  --sidebar-bg: #ffffff;
  --sidebar-hover-bg: rgba(170, 240, 209, 0.15);
  --sidebar-active-bg: linear-gradient(90deg, rgba(197, 160, 89, 0.1) 0%, rgba(197, 160, 89, 0.02) 100%);
  --sidebar-text: #334155;
  --sidebar-icon: #9a7b3c;
  --sidebar-border: rgba(15, 23, 42, 0.06);

  padding: 0 !important;
  margin: 0;
  font-family: "Tajawal", system-ui, sans-serif !important;
  background: transparent !important;
}

html[data-theme="dark"] body.maestro-mazer,
html[data-bs-theme="dark"] body.maestro-mazer {
  --sidebar-bg: #1e293b;
  --sidebar-hover-bg: rgba(255, 255, 255, 0.05);
  --sidebar-active-bg: linear-gradient(90deg, rgba(197, 160, 89, 0.15) 0%, transparent 100%);
  --sidebar-text: #cbd5e1;
  --sidebar-icon: #c5a059;
  --sidebar-border: rgba(255, 255, 255, 0.05);
}

/* إعدادات العرض والانزلاق للشريط الجانبي (منطقي حسب dir) */
body.maestro-mazer .maestro-mazer-sidebar.sidebar-wrapper,
body.maestro-mazer #sidebar .sidebar-wrapper {
  width: var(--maestro-mazer-sidebar-width) !important;
  background: var(--sidebar-bg) !important;
  box-shadow: 0 4px 24px rgba(0, 0, 0, 0.04) !important;
  border-inline-start: 1px solid var(--sidebar-border);
}

html[dir="rtl"] #sidebar .sidebar-wrapper {
  inset-inline-start: auto !important;
  inset-inline-end: calc(-1 * var(--maestro-mazer-sidebar-width)) !important;
  transition: inset-inline-end 0.4s cubic-bezier(0.25, 0.8, 0.25, 1) !important;
}

html[dir="rtl"] #sidebar ~ #main {
  margin-inline: 0 !important;
}

@media screen and (min-width: 1200px) {
  html[dir="rtl"] #sidebar .sidebar-wrapper {
    inset-inline-end: 0 !important;
    inset-inline-start: auto !important;
  }
  html[dir="rtl"] #sidebar ~ #main {
    margin-inline-end: var(--maestro-mazer-sidebar-width) !important;
    margin-inline-start: 0 !important;
    transition: margin-inline-end 0.4s ease;
  }
  body.maestro-mazer #section-tabs-sticky {
    display: none !important;
  }
}

html[dir="rtl"] #sidebar.active .sidebar-wrapper {
  inset-inline-end: 0 !important;
  inset-inline-start: auto !important;
}
html[dir="rtl"] #sidebar.active ~ #main {
  margin-inline-end: var(--maestro-mazer-sidebar-width) !important;
  margin-inline-start: 0 !important;
}
html[dir="rtl"] #sidebar.inactive .sidebar-wrapper {
  inset-inline-end: calc(-1 * var(--maestro-mazer-sidebar-width)) !important;
  inset-inline-start: auto !important;
}
html[dir="rtl"] #sidebar.inactive ~ #main {
  margin-inline-end: 0 !important;
}

/* رأس الشريط الجانبي (اللوجو) */
body.maestro-mazer .maestro-mazer-sidebar__header {
  padding-block-start: 1.5rem !important;
  padding-inline: 1.2rem !important;
  padding-block-end: 1rem !important;
  border-bottom: 1px solid var(--sidebar-border);
}

body.maestro-mazer .maestro-mazer-sidebar .logo a {
  font-size: 1.1rem;
  font-family: "Amiri", serif;
  font-weight: 700;
  color: var(--sidebar-text);
  letter-spacing: 0.02em;
  white-space: nowrap;
}

body.maestro-mazer .sidebar-menu {
  padding-block: var(--maestro-admin-space-block-md) !important;
  padding-inline: var(--maestro-admin-space-inline-sm) !important;
}

body.maestro-mazer #sidebar .sidebar-menu .sidebar-item {
  margin-block-end: 0.25rem;
}

/* =========================================================
   الإصلاح الجذري للأقسام الرئيسية (إلغاء تشوهات قالب Mazer)
   ========================================================= */
body.maestro-mazer #sidebar .sidebar-menu .sidebar-item > .sidebar-link {
  display: flex !important;
  align-items: center !important;
  padding-block: 0.8rem !important;
  padding-inline: 1.2rem !important;
  position: relative !important;
  border-radius: 12px;
  background: transparent;
  border: none;
  text-decoration: none !important;
  transition: background 0.25s ease, transform 0.25s ease;
}

body.maestro-mazer #sidebar .sidebar-menu .sidebar-item > .sidebar-link:hover {
  background: var(--sidebar-hover-bg);
  transform: translateX(-4px);
}

/* 1. الأيقونة: تثبيت الحجم لمنع الانضغاط */
body.maestro-mazer #sidebar .sidebar-menu .sidebar-item > .sidebar-link > i {
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
  font-size: 1.35rem !important;
  color: var(--sidebar-icon);
  margin: 0 !important;
  width: 28px !important;
  height: 28px !important;
  flex-shrink: 0 !important;
  transition: transform 0.3s ease;
}

body.maestro-mazer #sidebar .sidebar-menu .sidebar-item > .sidebar-link:hover > i {
  transform: scale(1.1);
}

/* 2. النص: إلغاء هوامش Mazer الفيزيائية + محاذاة منطقية */
body.maestro-mazer #sidebar .sidebar-menu .sidebar-item > .sidebar-link > span {
  margin-inline-start: var(--maestro-admin-space-inline-md) !important;
  margin-inline-end: 0 !important;
  font-size: 0.95rem !important;
  font-weight: 700 !important;
  color: var(--sidebar-text);
  white-space: nowrap !important;
  flex-grow: 1 !important;
  text-align: start !important;
}

/* 3. السهم (Chevron): تثبيت منطقي */
body.maestro-mazer #sidebar .sidebar-menu .sidebar-item.has-sub > .sidebar-link::after {
  position: absolute !important;
  inset-inline-start: 1.2rem !important;
  inset-inline-end: auto !important;
  top: 50% !important;
  transform: translateY(-50%) !important;
  margin: 0 !important;
  display: block !important;
}

/* =========================================================
   القائمة الفرعية (Submenu)
   ========================================================= */
body.maestro-mazer #sidebar .sidebar-menu .submenu {
  list-style: none;
  padding-inline-start: 3.2rem !important;
  padding-inline-end: 0 !important;
  margin-block-start: 0 !important;
  margin-block-end: var(--maestro-admin-space-block-xs) !important;
  background: transparent;
}

body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab {
  display: flex !important;
  align-items: center !important;
  width: 100%;
  padding-block: 0.6rem !important;
  padding-inline: 0.5rem !important;
  margin-block: 0.15rem !important;
  margin-inline: 0 !important;
  font-size: 0.88rem !important;
  font-weight: 500 !important;
  color: var(--sidebar-text) !important;
  background: transparent !important;
  border: none !important;
  border-radius: 8px !important;
  box-shadow: none !important;
  position: relative;
  transition: background 0.25s ease, transform 0.25s ease, color 0.25s ease;
  white-space: nowrap !important;
}

/* النقطة (Dot) بجانب الروابط الفرعية */
body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem::before,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab::before {
  content: "";
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background-color: rgba(154, 123, 60, 0.4);
  margin-inline-end: 10px !important;
  margin-inline-start: 0 !important;
  flex-shrink: 0;
  transition: background-color 0.25s ease, transform 0.25s ease;
}

body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem:hover,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab:hover {
  background: var(--sidebar-hover-bg) !important;
  color: var(--sidebar-icon) !important;
  transform: translateX(-4px);
}

body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem:hover::before,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab:hover::before {
  background-color: var(--sidebar-icon);
  transform: scale(1.5);
}

body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem.active,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab.active {
  background: var(--sidebar-active-bg) !important;
  color: var(--sidebar-icon) !important;
  font-weight: 800 !important;
  border-inline-start: 3px solid var(--sidebar-icon) !important;
  border-start-start-radius: 8px;
  border-end-start-radius: 8px;
  border-start-end-radius: 0;
  border-end-end-radius: 0;
}

body.maestro-mazer #sidebar .sidebar-menu a.section-tab.section-tab--subitem.active::before,
body.maestro-mazer #sidebar .sidebar-menu .submenu-link.section-tab.active::before {
  background-color: var(--sidebar-icon);
  box-shadow: 0 0 8px rgba(197, 160, 89, 0.6);
}

